ListNode *search(ListNode *first, DataType k) {
    ListNode *current = first;
    while (current) {
        if (current->data == k) return current;
        current = current->next;
    }
    return nullptr;
}

struct GenListNode {
    bool tag;          // false = atom, true = sublist
    GenListNode* next; // next node ở cùng level
    union {
        DataType    data; // dùng khi tag == false
        GenListNode* down; // dùng khi tag == true (trỏ vào sub-list)
    };
};
